from vex import verify

def latency_profile_chain(chain):
    def instrumented_invoke(input):
        steps = []

        def timed_step(step_name, fn):
            start = time.time()
            result = verify(fn)
            steps.append({'step': step_name, 'latency': time.time() - start})
            return result

        result = chain.invoke(input, config={
            'step_metrics': steps
        })

        slow_steps = [s for s in steps if s['latency'] > 5]
        if slow_steps:
            print(f'🚨 SLOW STEPS: {slow_steps}')
        return result
    return instrumented_invoke

